export const script = "\ndocument.getElementById('herovid').src='/agencia.mp4';\n/* ---- geolocation by timezone (no permission needed) ---- */\n(function(){\n  var map={'America/Toronto':'Toronto','America/Vancouver':'Vancouver','America/Edmonton':'Alberta','America/Winnipeg':'Winnipeg','America/Halifax':'Halifax',\n    'America/New_York':'New York','America/Chicago':'Texas','America/Denver':'Colorado','America/Phoenix':'Arizona','America/Los_Angeles':'California',\n    'America/Detroit':'Michigan','America/Miami':'Miami','America/Boston':'Boston','America/Houston':'Texas'};\n  try{var tz=Intl.DateTimeFormat().resolvedOptions().timeZone;var city=map[tz]||(tz&&tz.split('/')[1]?tz.split('/')[1].replace(/_/g,' '):'your area');\n    document.getElementById('geo').textContent=city+\"'s most trusted business solutions agency\";}catch(e){}\n})();\n\n/* ---- phone project slider synced with side cards ---- */\nvar projects=[\n  {title:'Restaurant Rebrand',grad:'linear-gradient(150deg,#10BEB2,#0a6f68)',lbl:'Branding \u00b7 Website \u00b7 Menus',\n   desc:'A full rebrand plus an online-ordering website that made the brand feel premium and modern.',\n   chips:['Branding','Website','Online Ordering'],\n   stars:'\u2605\u2605\u2605\u2605\u2605',quote:'Reservations doubled in our first month after launch. Worth every penny.',nm:'Mar\u00eda R.',rl:'Owner, La Cocina'},\n  {title:'Contractor Website',grad:'linear-gradient(150deg,#222A2E,#3a464b)',lbl:'Web Design \u00b7 Local SEO',\n   desc:'A lead-generating website with local SEO so the phone actually rings with new jobs.',\n   chips:['Web Design','Local SEO','Leads'],\n   stars:'\u2605\u2605\u2605\u2605\u2605',quote:'Calls went up about 60%. These guys just get it done.',nm:'Carlos T.',rl:'Owner, TR Contracting'},\n  {title:'Retail Launch Campaign',grad:'linear-gradient(150deg,#13c9bb,#0b7e76)',lbl:'Social \u00b7 Print \u00b7 Signage',\n   desc:'A coordinated launch across social media, print, and in-store signage for a grand opening.',\n   chips:['Social Ads','Print','Signage'],\n   stars:'\u2605\u2605\u2605\u2605\u2605',quote:'Best opening season we have ever had. The signage was gorgeous.',nm:'Jenny L.',rl:'Owner, Bloom Boutique'}\n];\nvar screen=document.getElementById('screen'),descEl=document.getElementById('desc'),testiEl=document.getElementById('testi'),dotsEl=document.getElementById('dots');\nprojects.forEach(function(p,i){\n  var s=document.createElement('div');s.className='slide'+(i===0?' active':'');\n  s.innerHTML='<div class=\"img\" style=\"background:'+p.grad+'\"></div>';\n  screen.appendChild(s);\n  var d=document.createElement('div');d.className='d'+(i===0?' on':'');d.onclick=function(){go(i)};dotsEl.appendChild(d);\n});\nfunction render(i){var p=projects[i];\n  descEl.className='info-card fade-swap';\n  descEl.innerHTML='<div class=\"tag\">Project</div><h3>'+p.title+'</h3><p>'+p.desc+'</p><div class=\"chips\" style=\"display:flex;gap:6px;flex-wrap:wrap;margin-top:14px\">'+p.chips.map(function(c){return '<span class=\\\"chip\\\" style=\\\"font-size:11px;font-weight:700;color:#0E9E95;background:#eafaf7;border-radius:999px;padding:5px 11px\\\">'+c+'</span>'}).join('')+'</div>';\n  testiEl.className='info-card fade-swap';\n  testiEl.innerHTML='<div class=\"tag\">What they said</div><div class=\"stars\">'+p.stars+'</div><p>\"'+p.quote+'\"</p><div class=\"who\"><div class=\"av\"></div><div><div class=\"nm\">'+p.nm+'</div><div class=\"rl\">'+p.rl+'</div></div></div>';\n  setTimeout(function(){descEl.classList.remove('fade-swap');testiEl.classList.remove('fade-swap')},520);\n}\nvar cur=0;function go(i){cur=i;\n  document.querySelectorAll('.slide').forEach(function(s,k){s.classList.toggle('active',k===i)});\n  document.querySelectorAll('.dots .d').forEach(function(d,k){d.classList.toggle('on',k===i)});\n  render(i);}\nrender(0);\nvar timer=setInterval(function(){go((cur+1)%projects.length)},3800);\n\n/* ---- pricing tabs ---- */\ndocument.querySelectorAll('.tab').forEach(function(t){t.onclick=function(){\n  document.querySelectorAll('.tab').forEach(function(x){x.classList.remove('on')});t.classList.add('on');\n  document.querySelectorAll('.pane').forEach(function(p){p.classList.remove('on')});\n  document.getElementById(t.dataset.pane).classList.add('on');}});\n\n/* ---- faq accordion ---- */\ndocument.querySelectorAll('.qa .q').forEach(function(q){q.onclick=function(){q.parentElement.classList.toggle('open')}});\n\n/* ---- count-up stats (overlapping hero) ---- */\nfunction countUp(el){var t=+el.dataset.count,dur=1200,st=performance.now();\n  function tick(now){var p=Math.min((now-st)/dur,1);el.textContent=Math.floor(p*t);if(p<1)requestAnimationFrame(tick);else el.textContent=t;}\n  requestAnimationFrame(tick);}\nvar sbDone=false,sb=document.getElementById('statbar');\nif(sb){var io2=new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting&&!sbDone){sbDone=true;sb.querySelectorAll('[data-count]').forEach(countUp);}})},{threshold:.4});io2.observe(sb);}\n\n/* ---- reveal on scroll (loading effect) ---- */\nvar io=new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}})},{threshold:.14});\ndocument.querySelectorAll('.rv,.stagger').forEach(function(el){io.observe(el)});\n/* reveal hero immediately */\nsetTimeout(function(){document.querySelectorAll('.hero .rv,.hero .stagger').forEach(function(e){e.classList.add('in')})},120);\n";
